script:
export const meta = {
  name: 'pass8-confirm',
  description: 'Pass-8: two independent agents confirm each of the 8 fixes is appropriate AND complete',
  phases: [{ title: 'Confirm' }],
}

const REPO = '/Users/[REDACTED]/hc-assay'

const SCHEMA = {
  type: 'object',
  additionalProperties: false,
  required: ['verdict', 'appropriate', 'complete', 'rationale', 'concerns'],
  properties: {
    verdict: { type: 'string', enum: ['CONFIRMED', 'CONCERN', 'REJECTED'] },
    appropriate: { type: 'boolean' },
    complete: { type: 'boolean' },
    rationale: { type: 'string' },
    concerns: { type: 'array', items: { type: 'string' } },
  },
}

const FINDINGS = [
  { key: 'K-CI-2', desc: `CI ran the bare \`pytest\` console script which does not put the repo root on sys.path, so \`from tests import ...\` failed at collection (ModuleNotFoundError: No module named 'tests') — the suite never ran in CI. Fix: pyproject [tool.pytest.ini_options] pythonpath now ["src", "."] so the \`tests\` package imports under bare \`pytest\` too. Verify: \`cd ${REPO} && source .venv/bin/activate && pytest -q --co 2>&1 | tail -2\` collects (was ModuleNotFoundError). Test: test_pytest_path_includes_repo_root_so_tests_package_imports.` },
  { key: 'K-CI-1', desc: `core (no-extras) lane mypy --strict failed: seam.py's guarded \`import httpx\` has no stub when the reasoning extra isn't installed. Fix: "httpx.*" added to [[tool.mypy.overrides]] ignore_missing_imports. Test: test_mypy_ignores_httpx_missing_stub_in_core_lane. Verify mypy still passes.` },
  { key: 'K-OPS-1', desc: `The lockfile-sync "reproducibility guard" re-resolved against live PyPI (no --exclude-newer), going red whenever any in-range transitive published — it was failing on clean checkouts (main CI red). Fix: a single committed date file .uv-exclude-newer (2026-06-14T00:00:00Z) is read by BOTH ci.yml (3 compile commands) and scripts/regenerate_lockfiles.sh, passing --exclude-newer so resolution is pinned to a point-in-time index. The cutoff was chosen clear of a boundary release (arize-phoenix 17.6/17.7) where uv resolution was non-deterministic. All three locks regenerated. VERIFY reproducibility: run the regen and a fresh \`uv pip compile ... --exclude-newer "$(cat .uv-exclude-newer | tr -d '[:space:]')"\` and confirm the non-comment content matches the committed requirements.lock (uv 0.11.21 is available locally). Tests: test_lockfile_sync_is_resolution_pinned.` },
  { key: 'K-REL-1', desc: `SIGTERM trace-flush handler (observability/tracing.py _install_flush_on_exit._handler) swallowed termination when the prior disposition was SIG_DFL (the default, non-callable): it flushed then returned, so the process no longer died on SIGTERM (docker stop/kill hang until SIGKILL). Fix: when prior == SIG_DFL, re-establish SIG_DFL and os.kill(getpid, signum) to re-deliver the default terminate; chain a callable prior; SIG_IGN stays ignored. Test: test_sigterm_handler_redelivers_default_termination (and the existing test updated). VERIFY the fix re-delivers and the test discriminates (would fail if reverted to the bare \`if callable(prior)\`).` },
  { key: 'K-OBS-2', desc: `pipeline.py _log_trail: a hashable-but-non-JSON payload value (bytes/datetime — freeze() only rejects UNhashable) caused json.dump to raise TypeError INSIDE the NamedTemporaryFile(delete=False) block BEFORE \`path = fh.name\`, orphaning the temp file (cleanup unreachable) AND silently dropping the #G-009 artifact (track() swallowed it, no warning). Fix: serialize up front with json.dumps(..., default=str) (so it can't raise mid-write and the artifact still attaches), open the temp file with fh.name always assigned so the finally cleanup is reachable, and add a _log.warning in track() so a tracker failure is no longer silent. Test: test_provenance_artifact_survives_non_json_evidence. VERIFY no temp-file leak AND the artifact attaches with such a value.` },
  { key: 'K-SEC-1', desc: `_local.py require_local_uri rejected libpq Unix-domain-socket hosts (leading "/", e.g. host=/var/run/postgresql) as non-loopback — the most data-sovereign connection (never touches the network), while TCP loopback was accepted. Fix: new is_local_socket_path() accepts a single leading-"/" path (rejects UNC // and /\\); applied in both the query-host and DSN-keyword branches. Tests: test_require_local_uri_accepts_unix_domain_socket, test_require_local_uri_still_rejects_unc_socket_lookalikes. VERIFY the socket forms are accepted and //evil/share still rejected.` },
  { key: 'K-OPS-2', desc: `scripts/regenerate_lockfiles.sh (the one documented remediation, referenced by dependabot.yml + CI errors) did not regenerate requirements-build.lock, which CI gates — a maintainer stayed red on a build-backend bump with no scripted fix. Fix: the script now regenerates all three locks (incl. requirements-build.lock) with --exclude-newer; CI error messages point at the script. Test: test_regenerate_script_covers_all_gated_lockfiles.` },
  { key: 'K-OPS-3', desc: `The integration job ran \`pytest --cov\` with NO --cov-fail-under, so the coverage gate was vacuous (exits 0 at any level). Fix: --cov-fail-under=90 added (current coverage ~96.6%). Test: test_coverage_floor_is_enforced. VERIFY the floor is present and current coverage exceeds it.` },
]

function prompt(f, lens) {
  return `You are an independent, adversarial fix-confirmation reviewer (reviewer ${lens}) for the hc-assay production-hardening campaign, repo at ${REPO} (branch harden/pass-8, latest commit). Your job: confirm the fix is BOTH appropriate (correct root cause, sound approach, right layer) AND complete (no residual gap; the regression test actually DISCRIMINATES — fails if the fix is reverted). Be skeptical; try to find a hole.

FINDING ${f.key}:
${f.desc}

Read the actual changed files and run what you can (cd ${REPO} && source .venv/bin/activate && python -m pytest -q <path> — use "python -m pytest", not bare pytest, for your own runs; uv 0.11.21 is available for K-OPS-1). Judge ONLY ${f.key}. Return CONFIRMED only if appropriate AND complete; CONCERN if appropriate but a real residual gap remains (name it); REJECTED if wrong or non-discriminating. List concrete concerns (empty if none).`
}

phase('Confirm')
const results = await parallel(
  FINDINGS.flatMap((f) => [
    () => agent(prompt(f, 'A'), { label: `confirm:${f.key}:A`, phase: 'Confirm', schema: SCHEMA }).then((v) => ({ key: f.key, lens: 'A', v })),
    () => agent(prompt(f, 'B'), { label: `confirm:${f.key}:B`, phase: 'Confirm', schema: SCHEMA }).then((v) => ({ key: f.key, lens: 'B', v })),
  ])
)

const clean = results.filter(Boolean)
const byKey = {}
for (const r of clean) {
  byKey[r.key] = byKey[r.key] || []
  byKey[r.key].push({ lens: r.lens, ...r.v })
}
const summary = Object.entries(byKey).map(([key, votes]) => {
  const bothConfirmed = votes.length === 2 && votes.every((x) => x.verdict === 'CONFIRMED')
  return { key, bothConfirmed, votes }
})
log('PASS-8 FIX CONFIRMATION:')
for (const s of summary) log(`${s.key}: ${s.bothConfirmed ? 'BOTH-CONFIRMED' : 'NEEDS-ATTENTION'} — ${s.votes.map((v) => v.lens + ':' + v.verdict).join(', ')}`)
return { summary }
